const { ImapFlow } = imapflowPkg;
const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const FAILURE_THRESHOLD = 3;

const creds = global.get('config')?.secrets?.gmail;
if (!creds?.account || !creds?.app_password) {
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('Missing Gmail creds') });
    node.error('Gmail credentials not found in config.secrets.gmail');
    return null;
}

// --- Helpers ---

function isAuthError(errMessage) {
    if (!errMessage) return false;
    const msg = errMessage.toLowerCase();
    return msg.includes('authentication') ||
           msg.includes('invalid credentials') ||
           msg.includes('auth failed') ||
           msg.includes('login failed');
}

function handleRecovery() {
    const activeNotification = flow.get('imap_notification_sent');
    if (activeNotification) {
        // Clear the notification
        node.send([null, {
            topic: 'highland/command/notify/clear',
            payload: {
                notification_id: 'email_ingress.imap_failure',
                correlation_id: activeNotification
            }
        }]);
        flow.set('imap_notification_sent', null);
        flow.set('imap_last_failure_tier', null);
        node.warn(`IMAP recovered; cleared notification ${activeNotification}`);
    }
    flow.set('imap_consecutive_failures', 0);
}

function handleFailure(err) {
    const failures = (flow.get('imap_consecutive_failures') || 0) + 1;
    flow.set('imap_consecutive_failures', failures);
    flow.set('imap_last_failure_at', Date.now());
    flow.set('imap_last_error', err.message);

    if (failures < FAILURE_THRESHOLD) {
        node.warn(`IMAP connection failure ${failures}/${FAILURE_THRESHOLD}: ${err.message}`);
        return;
    }

    if (flow.get('imap_notification_sent')) {
        node.warn(`IMAP still failing (${failures} consecutive); notification already active`);
        return;
    }

    // Threshold crossed — publish notification
    const tier = isAuthError(err.message) ? 'auth' : 'connection';
    const correlationId = `email_ingress_imap_failure_${Date.now()}`;

    const notification = tier === 'auth' ? {
        notification_id: 'email_ingress.imap_failure',
        timestamp: new Date().toISOString(),
        source: 'email_ingress',
        title: 'Email Ingress: IMAP authentication failed',
        message: `Gmail app password appears to be invalid. Regenerate in Google Account security settings and update secrets.json. Error: ${err.message}`,
        correlation_id: correlationId,
        sticky: true
    } : {
        notification_id: 'email_ingress.imap_failure',
        timestamp: new Date().toISOString(),
        source: 'email_ingress',
        title: 'Email Ingress: IMAP connection failing',
        message: `Cannot establish connection to Gmail IMAP after ${failures} attempts. Mail is not flowing. Error: ${err.message}`,
        correlation_id: correlationId,
        sticky: true
    };

    node.send([null, {
        topic: 'highland/event/notify',
        payload: notification
    }]);

    flow.set('imap_notification_sent', correlationId);
    flow.set('imap_last_failure_tier', tier);
    node.warn(`IMAP failure threshold crossed (${failures}); published ${tier} notification`);
}

// --- Main logic ---

// Reuse existing healthy connection if present
const existing = flow.get('imap_client', 'volatile');
if (existing && existing.usable) {
    // Healthy reuse — clear any stale notification, reset failure counter
    handleRecovery();

    const connectedAt = flow.get('imap_connected_at') || Date.now();
    const ageSec = Math.floor((Date.now() - connectedAt) / 1000);
    node.status({ fill: 'green', shape: 'dot', text: formatStatus(`Reused (age ${ageSec}s)`) });
    msg.payload = { reused: true, age_seconds: ageSec };
    return [msg, null];
}

// Open a fresh connection
node.status({ fill: 'yellow', shape: 'ring', text: formatStatus('Connecting...') });

(async () => {
    const client = new ImapFlow({
        host: 'imap.gmail.com',
        port: 993,
        secure: true,
        auth: {
            user: creds.account,
            pass: creds.app_password.replace(/\s+/g, '')
        },
        logger: false
    });

    client.on('error', (err) => {
        node.warn(`IMAP error event: ${err.message}`);
        if (flow.get('imap_client', 'volatile') === client) {
            flow.set('imap_client', null, 'volatile');
            flow.set('imap_connected_at', null);
        }
    });

    client.on('close', () => {
        //node.warn('IMAP close event');
        if (flow.get('imap_client', 'volatile') === client) {
            flow.set('imap_client', null, 'volatile');
            flow.set('imap_connected_at', null);
        }
    });

    try {
        await client.connect();
        flow.set('imap_client', client, 'volatile');
        flow.set('imap_connected_at', Date.now());
        handleRecovery();
        node.status({ fill: 'green', shape: 'dot', text: formatStatus('Connected (fresh)') });
        node.send([{ payload: { reused: false, connected_at: new Date().toISOString() } }, null]);
    } catch (err) {
        flow.set('imap_client', null, 'volatile');
        flow.set('imap_connected_at', null);
        node.status({ fill: 'red', shape: 'ring', text: formatStatus(`Error: ${err.message}`) });
        node.error(`IMAP connect failed: ${err.message}`);
        handleFailure(err);
    }
})();

return null;

finalize:
const client = flow.get('imap_client', 'volatile');
if (client) {
    // Fire-and-forget logout — Node-RED doesn't wait on async in On Stop
    client.logout().catch(() => { /* swallow */ });
    flow.set('imap_client', null, 'volatile');
    flow.set('imap_connected_at', null);
    //node.warn('Connection closed on stop');
}

