const client = flow.get('imap_client', 'volatile');
const lock = flow.get('imap_idle_lock', 'volatile');

if (lock) {
    try { lock.release(); } catch (_) {}
    flow.set('imap_idle_lock', null, 'volatile');
    flow.set('imap_idle_running', false, 'volatile');
}

if (!client) {
    node.status({ fill: 'grey', shape: 'ring', text: formatStatus('Nothing to disconnect') });
    msg.payload = { disconnected: false, reason: 'no_client' };
    return msg;
}

(async () => {
    try {
        await client.logout();
        flow.set('imap_client', null, 'volatile');
        flow.set('imap_connected_at', null);
        node.status({ fill: 'grey', shape: 'ring', text: formatStatus('Disconnected') });
        node.send({ payload: { disconnected: true } });
    } catch (err) {
        flow.set('imap_client', null, 'volatile');
        flow.set('imap_connected_at', null);
        node.status({ fill: 'red', shape: 'ring', text: formatStatus(`Logout error: ${err.message}`) });
        node.send({ payload: { disconnected: true, error: err.message } });
    }
})();

return null;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const WATCH_FOLDER = '[Gmail]/All Mail';
const LABEL_PREFIX = 'Highland/';

const client = flow.get('imap_client', 'volatile');
if (!client || !client.usable) {
    node.status({ fill: 'red', shape: 'ring', text: formatStatus('No usable client') });
    node.error('Start watcher called with no connection');
    return null;
}

if (flow.get('imap_idle_running', 'volatile')) {
    node.status({ fill: 'green', shape: 'dot', text: formatStatus('Already watching') });
    return null;
}

node.status({ fill: 'yellow', shape: 'ring', text: formatStatus('Starting watcher...') });

(async () => {
    try {
        const lock = await client.getMailboxLock(WATCH_FOLDER);
        flow.set('imap_idle_lock', lock, 'volatile');
        flow.set('imap_idle_running', true, 'volatile');

        // Establish or recover baseline UID
        const status = await client.status(WATCH_FOLDER, { uidNext: true });
        const newUidBaseline = status.uidNext - 1;
        const savedLastUid = flow.get('imap_last_uid_all_mail');
        const baseline = (savedLastUid !== undefined && savedLastUid !== null)
            ? savedLastUid
            : newUidBaseline;
        if (savedLastUid === undefined || savedLastUid === null) {
            flow.set('imap_last_uid_all_mail', newUidBaseline);
            node.warn(`First run: baseline set to uidNext - 1 = ${newUidBaseline}`);
        } else {
            //node.warn(`Resuming from last saved UID ${baseline} (current uidNext - 1 = ${newUidBaseline})`);
            // Catch up anything that arrived while we were down
            if (newUidBaseline > baseline) {
                node.warn(`Catching up UIDs ${baseline + 1}..${newUidBaseline}`);
                await processRange(baseline + 1, newUidBaseline);
            }
        }

        node.status({
            fill: 'green',
            shape: 'dot',
            text: formatStatus(`Watching ${WATCH_FOLDER}`)
        });

        // Per-message processor — fetches with labels, filters, emits
        async function processRange(fromUid, toUid) {
            for await (const m of client.fetch(
                `${fromUid}:${toUid}`,
                { uid: true, envelope: true, labels: true },
                { uid: true }
            )) {
                const labels = Array.from(m.labels || []);
                const highlandLabel = labels.find(l => l.startsWith(LABEL_PREFIX));

                flow.set('imap_last_uid_all_mail', m.uid);

                if (!highlandLabel) continue;  // silently drop non-Highland

                const derivedLabel = highlandLabel
                    .slice(LABEL_PREFIX.length)
                    .toLowerCase()
                    .replace(/\s+/g, '_');

                node.send({
                    payload: {
                        uid: m.uid,
                        message_id: m.envelope?.messageId || null,
                        gmail_label: highlandLabel,
                        label: derivedLabel,
                        envelope: m.envelope,
                        all_labels: labels
                    }
                });
            }
        }

        // Event handler for new mail
        client.on('exists', async (data) => {
            if (data.path !== WATCH_FOLDER) return;
            try {
                const lastUid = flow.get('imap_last_uid_all_mail') || 0;
                const newStatus = await client.status(WATCH_FOLDER, { uidNext: true });
                const highWater = newStatus.uidNext - 1;
                if (highWater <= lastUid) return;
                await processRange(lastUid + 1, highWater);
            } catch (err) {
                node.warn(`Error in exists handler: ${err.message}`);
            }
        });

    } catch (err) {
        flow.set('imap_idle_running', false, 'volatile');
        flow.set('imap_idle_lock', null, 'volatile');
        node.status({ fill: 'red', shape: 'ring', text: formatStatus(`Watcher failed: ${err.message}`) });
        node.error(`Watcher start failed: ${err.message}`);
    }
})();

return null;

finalize:
const lock = flow.get('imap_idle_lock', 'volatile');
if (lock) {
    try { lock.release(); } catch (_) { }
}
flow.set('imap_idle_lock', null, 'volatile');
flow.set('imap_idle_running', false, 'volatile');

